class Solution:
    def wateringPlants(self, plants, capacity):
        x = -1
        water = capacity
        steps = 0
        for i, need in enumerate(plants):
            if water < need:
                while x > -1:
                    x -= 1
                    steps += 1
                water = capacity
            while x < i:
                x += 1
                steps += 1
            water -= need
        return steps

