class Solution:
    def wateringPlants(self, plants: list, capacity: int) -> int:
        water = capacity
        pos = -1
        steps = 0
        for i, need in enumerate(plants):
            if water < need:
                steps += pos + 1
                water = capacity
                steps += i + 1
            else:
                steps += i - pos
            pos = i
            water -= need
        return steps

