var wateringPlants = function(plants, capacity) {
    let water = capacity;
    let pos = -1;
    let steps = 0;
    for (let i = 0; i < plants.length; i++) {
        const need = plants[i];
        if (water < need) {
            steps += pos + 1;
            water = capacity;
            steps += i + 1;
        } else {
            steps += i - pos;
        }
        pos = i;
        water -= need;
    }
    return steps;
};
